// Prepara os dados para o prompt - UNIFICADO (resposta + extração em 1 chamada)
const fase = $input.first().json.Fase || 'inicio';
const dados = $input.first().json.Dados || '{}';
const historico = $input.first().json.Historico || '';
const msg = $input.first().json.msg || $json.body?.messages?.[0]?.text?.body || '';

return {
  fase: fase,
  dados: dados,
  ultima_msg: msg,
  historico: historico,
  telefone: $input.first().json.Telefone
};

// Extrai dados da resposta da IA sem chamar Ollama novamente
const resposta = $json.message?.content || '';

let nome = null, ramo = null, interesse = 'medio', servico_interesse = null;
let objecao = null, pronto_pagamento = false, quer_humano = false;

// Detecta padrões na resposta
const lower = resposta.toLowerCase();

if (lower.includes('link') || lower.includes('pagamento') || lower.includes('comprar') || lower.includes('fechar')) {
  pronto_pagamento = true;
}
if (lower.includes('humano') || lower.includes('atendente') || lower.includes('pessoa') || lower.includes('ligação')) {
  quer_humano = true;
}
if (lower.includes('caro') || lower.includes('preço') || lower.includes('$$') || lower.includes('muito caro')) {
  objecao = 'preço';
} else if (lower.includes('pensar') || lower.includes('depois') || lower.includes('volto')) {
  objecao = 'pensar';
}
if (lower.includes('site') || lower.includes('website')) servico_interesse = 'site';
if (lower.includes('solo') || lower.includes('plano solo')) servico_interesse = 'saas_solo';
if (lower.includes('equipe') || lower.includes('plano equipe')) servico_interesse = 'saas_equipe';
if (lower.includes('corporativo') || lower.includes('plano corporativo')) servico_interesse = 'saas_corporativo';

// Extrai nome do histórico (primeiro nome mencionado)
const historico = $json.historico || '';
const nomeMatch = historico.match(/nome[\s\:]+([A-ZÀ-Ú][a-zà-ú]+)/i);
if (nomeMatch) nome = nomeMatch[1];

return {
  nome: nome,
  ramo: ramo,
  interesse: interesse,
  servico_interesse: servico_interesse,
  objecao: objecao,
  pronto_pagamento: pronto_pagamento,
  quer_humano: quer_humano,
  resposta: resposta,
  historico: $json.historico,
  ultima_msg: $json.ultima_msg,
  telefone: $json.telefone
};

const dados = $input.first().json;
// Atualiza estado - extrai dados do objeto retornado pelo nó anterior
return {
  fase: dados.pronto_pagamento ? 'pagamento' : (dados.quer_humano ? 'agendar' : 'qualificacao'),
  dados: JSON.stringify({ nome: dados.nome, ramo: dados.ramo, necessidade: dados.servico_interesse, interesse: dados.interesse, objecao: dados.objecao }),
  historico: (dados.historico || '') + '\nCliente: ' + dados.ultima_msg + '\nIA: ' + dados.resposta,
  telefone: dados.telefone
};
